import React, { useState, useMemo } from 'react';

const theme = {
  bg: '#0a0a0a', surface: '#111111', surfaceAlt: '#1a1a1a',
  border: '#2a2a2a', text: '#fafafa', textSec: '#a1a1aa', textMuted: '#52525b',
  blue: '#38bdf8', pink: '#f472b6', yellow: '#fbbf24', green: '#a3e635',
  orange: '#fb923c', purple: '#a855f7',
};

const GROUP_COLORS = [theme.blue, theme.pink, theme.yellow, theme.green];

const INPUT = [
  [[9,11,10],[12,8,10],[11,9,10]],
  [[7,9,8],[6,8,7],[9,7,8]],
  [[2,3,1],[4,2,3],[1,3,2]],
  [[5,6,4],[7,5,6],[4,6,5]],
];

const EPS = 1e-5;

function computeGN(X, numGroups) {
  const C = X.length, H = X[0].length, W = X[0][0].length;
  const gs = C / numGroups;
  const output = [], stats = [];
  for (let g = 0; g < numGroups; g++) {
    let sum = 0, cnt = 0;
    for (let c = g*gs; c < (g+1)*gs; c++)
      for (let h = 0; h < H; h++)
        for (let w = 0; w < W; w++) { sum += X[c][h][w]; cnt++; }
    const mean = sum / cnt;
    let vSum = 0;
    for (let c = g*gs; c < (g+1)*gs; c++)
      for (let h = 0; h < H; h++)
        for (let w = 0; w < W; w++) vSum += (X[c][h][w] - mean) ** 2;
    const variance = vSum / cnt;
    stats.push({ mean, variance, channels: Array.from({length: gs}, (_, i) => g*gs+i) });
    for (let c = g*gs; c < (g+1)*gs; c++) {
      const ch = [];
      for (let h = 0; h < H; h++) {
        const row = [];
        for (let w = 0; w < W; w++)
          row.push((X[c][h][w] - mean) / Math.sqrt(variance + EPS));
        ch.push(row);
      }
      output.push(ch);
    }
  }
  return { output, stats };
}

function inputColor(val) {
  const t = (val - 1) / 11;
  return `rgb(${Math.round(35+t*195)},${Math.round(28+t*155)},${Math.round(20+t*50)})`;
}

function outputColor(val) {
  const t = Math.max(0, Math.min(1, (val + 2.5) / 5));
  if (t < 0.5) {
    const s = t / 0.5;
    return `rgb(${Math.round(25+s*25)},${Math.round(40+s*45)},${Math.round(100+s*55)})`;
  }
  const s = (t - 0.5) / 0.5;
  return `rgb(${Math.round(50+s*190)},${Math.round(85+s*110)},${Math.round(50+s*10)})`;
}

function textColor(val, isOutput) {
  if (isOutput) return Math.abs(val) < 0.8 ? '#888' : '#eee';
  return val > 6 ? '#000' : '#ddd';
}

export default function App() {
  const [numGroups, setNumGroups] = useState(2);
  const [hover, setHover] = useState(null);

  const { output, stats } = useMemo(() => computeGN(INPUT, numGroups), [numGroups]);
  const gs = 4 / numGroups;

  const groupOf = (c) => Math.floor(c / gs);
  const hoveredGroup = hover ? groupOf(hover.c) : null;

  const labels = { 1: 'Layer Norm', 2: 'Group Norm', 4: 'Instance Norm' };

  const CELL = 28, PAD = 2;
  const gridW = 3 * CELL + 2 * PAD;

  const renderGrid = (data, cIdx, isOutput) => {
    const gIdx = groupOf(cIdx);
    const color = GROUP_COLORS[gIdx % GROUP_COLORS.length];
    const highlighted = hoveredGroup === gIdx;
    return (
      <div key={`${isOutput?'o':'i'}-${cIdx}`} style={{
        display: 'inline-block', verticalAlign: 'top',
      }}>
        <div style={{
          fontSize: 10, textAlign: 'center', marginBottom: 3,
          color: highlighted ? color : theme.textMuted,
          fontWeight: highlighted ? 700 : 400,
          transition: 'all 0.25s',
        }}>Ch {cIdx}</div>
        <div style={{
          display: 'grid', gridTemplateColumns: `repeat(3, ${CELL}px)`,
          gap: PAD, borderRadius: 4, overflow: 'hidden',
        }}>
          {data.map((row, h) => row.map((val, w) => {
            const isHov = hover && hover.c === cIdx && hover.h === h && hover.w === w && hover.isOutput === isOutput;
            return (
              <div key={`${h}-${w}`}
                onMouseEnter={() => setHover({ c: cIdx, h, w, isOutput })}
                onMouseLeave={() => setHover(null)}
                style={{
                  width: CELL, height: CELL,
                  background: isOutput ? outputColor(val) : inputColor(val),
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontSize: 10, fontFamily: 'monospace', fontWeight: 600,
                  color: textColor(val, isOutput),
                  cursor: 'pointer',
                  outline: isHov ? `2px solid ${theme.text}` : 'none',
                  outlineOffset: -2,
                  transition: 'background 0.35s',
                }}>
                {isOutput ? val.toFixed(1) : val}
              </div>
            );
          }))}
        </div>
      </div>
    );
  };

  const renderGroupedRow = (dataArr, isOutput) => {
    const groups = [];
    for (let g = 0; g < numGroups; g++) {
      const color = GROUP_COLORS[g % GROUP_COLORS.length];
      const highlighted = hoveredGroup === g;
      const chIndices = Array.from({length: gs}, (_, i) => g*gs+i);
      groups.push(
        <div key={g} style={{
          display: 'flex', gap: 6,
          padding: '6px 8px', borderRadius: 8,
          border: `2px solid ${highlighted ? color : color + '40'}`,
          background: highlighted ? color + '0C' : 'transparent',
          transition: 'all 0.3s',
        }}>
          {chIndices.map(c => renderGrid(dataArr[c], c, isOutput))}
        </div>
      );
    }
    return (
      <div style={{ display: 'flex', gap: 8, justifyContent: 'center', flexWrap: 'wrap' }}>
        {groups}
      </div>
    );
  };

  const hovStat = hover ? stats[groupOf(hover.c)] : null;
  const hovInput = hover ? INPUT[hover.c][hover.h][hover.w] : null;
  const hovOutput = hover ? output[hover.c][hover.h][hover.w] : null;

  return (
    <div style={{
      minHeight: '100vh', background: theme.bg, color: theme.text,
      fontFamily: "'Inter', system-ui, sans-serif",
      display: 'flex', flexDirection: 'column', alignItems: 'center',
      padding: '20px 16px',
    }}>
      <div style={{ maxWidth: 560, width: '100%' }}>
        {/* Header */}
        <div style={{ textAlign: 'center', marginBottom: 16 }}>
          <h1 style={{ fontSize: 20, fontWeight: 700, margin: 0 }}>Group Normalization</h1>
          <p style={{ fontSize: 12, color: theme.textSec, margin: '4px 0 0' }}>
            Change the number of groups to see what gets normalized together
          </p>
        </div>

        {/* Group selector */}
        <div style={{ display: 'flex', justifyContent: 'center', gap: 6, marginBottom: 18 }}>
          {[1, 2, 4].map(n => {
            const active = numGroups === n;
            return (
              <button key={n} onClick={() => setNumGroups(n)} style={{
                padding: '8px 16px', border: 'none', borderRadius: 8, cursor: 'pointer',
                background: active ? theme.purple : theme.surface,
                color: active ? '#fff' : theme.textSec,
                fontSize: 12, fontWeight: 600,
                outline: active ? `2px solid ${theme.purple}` : `1px solid ${theme.border}`,
                outlineOffset: 0,
                transition: 'all 0.2s',
              }}>
                <div>{n} Group{n > 1 ? 's' : ''}</div>
                <div style={{ fontSize: 9, opacity: 0.7, marginTop: 1 }}>
                  {labels[n]}
                </div>
              </button>
            );
          })}
        </div>

        {/* Input */}
        <div style={{ marginBottom: 4 }}>
          <div style={{ fontSize: 11, color: theme.textMuted, textAlign: 'center', marginBottom: 6, fontWeight: 600, letterSpacing: 1, textTransform: 'uppercase' }}>
            Input (4 channels, 3x3)
          </div>
          {renderGroupedRow(INPUT, false)}
        </div>

        {/* Arrow */}
        <div style={{ textAlign: 'center', padding: '8px 0', fontSize: 11, color: theme.textMuted }}>
          <span style={{ fontSize: 16 }}>  </span> normalize per group
          <div style={{ fontSize: 18, lineHeight: 1 }}>v</div>
        </div>

        {/* Output */}
        <div style={{ marginBottom: 14 }}>
          <div style={{ fontSize: 11, color: theme.textMuted, textAlign: 'center', marginBottom: 6, fontWeight: 600, letterSpacing: 1, textTransform: 'uppercase' }}>
            Normalized Output
          </div>
          {renderGroupedRow(output, true)}
        </div>

        {/* Hover computation */}
        <div style={{
          background: theme.surface, borderRadius: 10, padding: '10px 14px',
          marginBottom: 12, minHeight: 54, border: `1px solid ${theme.border}`,
          transition: 'all 0.2s',
        }}>
          {hover && hovStat ? (
            <div style={{ fontFamily: 'monospace', fontSize: 11 }}>
              <div style={{ color: GROUP_COLORS[groupOf(hover.c)], fontWeight: 700, marginBottom: 4 }}>
                Ch{hover.c} [{hover.h},{hover.w}] - Group {groupOf(hover.c)}
              </div>
              <div style={{ color: theme.textSec, lineHeight: 1.6 }}>
                <span style={{ color: theme.orange }}>mean</span>={hovStat.mean.toFixed(2)}
                {'  '}
                <span style={{ color: theme.orange }}>var</span>={hovStat.variance.toFixed(2)}
                {'  '}
                <span style={{ color: theme.orange }}>std</span>={Math.sqrt(hovStat.variance + EPS).toFixed(2)}
              </div>
              <div style={{ color: theme.text, marginTop: 2 }}>
                ({hovInput} - {hovStat.mean.toFixed(2)}) / {Math.sqrt(hovStat.variance + EPS).toFixed(2)} = <span style={{ color: theme.green, fontWeight: 700 }}>{hovOutput.toFixed(3)}</span>
              </div>
            </div>
          ) : (
            <div style={{ color: theme.textMuted, fontSize: 11, textAlign: 'center', paddingTop: 8 }}>
              Hover over any cell to see the step-by-step computation
            </div>
          )}
        </div>

        {/* Group stats */}
        <div style={{ display: 'flex', gap: 8, marginBottom: 14, justifyContent: 'center', flexWrap: 'wrap' }}>
          {stats.map((s, g) => (
            <div key={g} style={{
              background: theme.surface, borderRadius: 8, padding: '8px 12px',
              borderLeft: `3px solid ${GROUP_COLORS[g % GROUP_COLORS.length]}`,
              flex: 1, minWidth: 100, maxWidth: 160,
            }}>
              <div style={{ fontSize: 10, fontWeight: 700, color: GROUP_COLORS[g % GROUP_COLORS.length], marginBottom: 3 }}>
                Group {g} <span style={{ fontWeight: 400, color: theme.textMuted }}>(Ch {s.channels.join(',')})</span>
              </div>
              <div style={{ fontSize: 10, fontFamily: 'monospace', color: theme.textSec }}>
                mean: {s.mean.toFixed(2)}
              </div>
              <div style={{ fontSize: 10, fontFamily: 'monospace', color: theme.textSec }}>
                var: {s.variance.toFixed(2)}
              </div>
            </div>
          ))}
        </div>

        {/* Insight */}
        <div style={{
          background: theme.surfaceAlt, borderRadius: 10, padding: '12px 14px',
          border: `1px solid ${theme.border}`,
        }}>
          <div style={{ fontSize: 12, fontWeight: 600, color: theme.purple, marginBottom: 4 }}>
            {numGroups === 1 ? 'All channels share one mean/variance' :
             numGroups === 4 ? 'Each channel has its own mean/variance' :
             `${numGroups} groups, ${gs} channels each`}
          </div>
          <div style={{ fontSize: 11, color: theme.textSec, lineHeight: 1.5 }}>
            {numGroups === 1
              ? 'With 1 group, all channels are normalized together (= Layer Norm). High-value channels (Ch0~10) and low-value channels (Ch2~2) share the same statistics, so their relative differences are preserved.'
              : numGroups === 4
              ? 'With 4 groups, each channel is normalized independently (= Instance Norm). Each channel\'s values center around 0 regardless of the other channels. No cross-channel information is shared.'
              : 'With 2 groups, similar-range channels share statistics. Ch0 (high) and Ch1 (medium-high) normalize together, while Ch2 (low) and Ch3 (medium) form another group. This balances between Layer Norm and Instance Norm.'}
          </div>
          <div style={{ fontSize: 10, color: theme.textMuted, marginTop: 6, fontStyle: 'italic' }}>
            Unlike Batch Norm, Group Norm works per-sample - no dependency on batch size.
          </div>
        </div>
      </div>
    </div>
  );
}
